const res = pw.response.body;

// Ambil data dasar
const token = res.data.token;
const userId = res.data.user.id;

// Ambil list koperasi (antisipasi kalau kosong)
const koperasiList = res.data.koperasi || [];

// Ambil koperasi pertama (default)
const koperasiId = koperasiList.length > 0 
  ? koperasiList[0].koperasi.id 
  : null;

// Optional: ambil semua koperasi id (kalau mau dipakai nanti)
const semuaKoperasiId = koperasiList.map(k => k.koperasi.id);

// Simpan ke environment
pw.env.set("token", token);
pw.env.set("user_id", String(userId));

// Simpan koperasi aktif (default)
if (koperasiId !== null) {
  pw.env.set("koperasi_id", String(koperasiId));
}

// Simpan semua koperasi (optional, bentuk JSON string)
pw.env.set("koperasi_list", JSON.stringify(semuaKoperasiId));


// Debug (biar gampang ngecek)
console.log("Token:", token);
console.log("User ID:", userId);
console.log("Koperasi aktif:", koperasiId);
console.log("Semua koperasi:", semuaKoperasiId);

